import{_ as t,o as s,c as i,ag as a}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Complex class blocked","description":"","frontmatter":{},"headers":[],"relativePath":"qa/method-complex.md","filePath":"qa/method-complex.md","lastUpdated":1782689832000}'),o={name:"qa/method-complex.md"};function n(l,e,r,p,d,h){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="complex-class-blocked" tabindex="-1">Complex class blocked <a class="header-anchor" href="#complex-class-blocked" aria-label="Permalink to &quot;Complex class blocked&quot;">​</a></h1><p>When a class is highly nested, recursive, or just very wide, EasyYapi stops expanding fields once a safety limit is reached. The remaining fields are silently dropped; an <code>INFO</code>-level log line is written to the IDE log:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Element limit exceeded while parsing &lt;qualified-name&gt;. Processed &lt;n&gt; elements. Stopping field expansion.</span></span></code></pre></div><h2 id="built-in-limits" tabindex="-1">Built-in limits <a class="header-anchor" href="#built-in-limits" aria-label="Permalink to &quot;Built-in limits&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Config key</th><th>Default</th><th>Meaning</th></tr></thead><tbody><tr><td><code>max.elements</code></td><td><code>512</code></td><td>Total number of fields that can be expanded in a single build operation.</td></tr><tr><td><code>max.deep</code></td><td><code>8</code></td><td>Maximum nesting depth when resolving fields of nested types.</td></tr></tbody></table><p>Both are read from any rule source (project, extension, remote, global). When the limit is hit, EasyYapi does <strong>not</strong> throw — it just stops expanding further fields for that response/request body.</p><h2 id="solutions" tabindex="-1">Solutions <a class="header-anchor" href="#solutions" aria-label="Permalink to &quot;Solutions&quot;">​</a></h2><h3 id="_1-raise-the-limits" tabindex="-1">1. Raise the limits <a class="header-anchor" href="#_1-raise-the-limits" aria-label="Permalink to &quot;1. Raise the limits&quot;">​</a></h3><p>If the class genuinely needs more fields, raise the limits in your <code>.easy.api.config</code>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">max.elements</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=2048</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">max.deep</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=16</span></span></code></pre></div><blockquote><p>Setting these too high can cause slow exports or OOM for pathological class graphs — raise incrementally.</p></blockquote><h3 id="_2-ignore-unnecessary-fields" tabindex="-1">2. Ignore unnecessary fields <a class="header-anchor" href="#_2-ignore-unnecessary-fields" aria-label="Permalink to &quot;2. Ignore unnecessary fields&quot;">​</a></h3><p>Exclude fields that don&#39;t need to be documented with <a href="./../settings/rules/field_ignore"><code>field.ignore</code></a>:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">field.ignore</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.name() == </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;complexField&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> || it.type().name().startsWith(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.internal.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="_3-convert-complex-types-to-simple-ones" tabindex="-1">3. Convert complex types to simple ones <a class="header-anchor" href="#_3-convert-complex-types-to-simple-ones" aria-label="Permalink to &quot;3. Convert complex types to simple ones&quot;">​</a></h3><p>Use <a href="./../settings/rules/json_rule_convert"><code>json.rule.convert</code></a> to replace a complex type with a simple one:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">json.rule.convert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:it.type().name()==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example.ComplexType&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> =&gt; java.util.Map</span></span></code></pre></div><h3 id="_4-override-the-return-type" tabindex="-1">4. Override the return type <a class="header-anchor" href="#_4-override-the-return-type" aria-label="Permalink to &quot;4. Override the return type&quot;">​</a></h3><p>If the method&#39;s declared return type is the source of the explosion, use <a href="./multiple-return-types"><code>method.return</code></a> to override it with a simpler one:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">method.return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example.SimpleResult&lt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> + it.returnType().name() + </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&gt;&quot;</span></span></code></pre></div><blockquote><p>Do <strong>not</strong> confuse this with <code>method.return.main</code>, which only chooses the field to attach the <code>@return</code> doc comment to — it does not change the response schema.</p></blockquote>`,21)])])}const m=t(o,[["render",n]]);export{u as __pageData,m as default};
